<?php
declare(strict_types=1);
require_once dirname(__DIR__) . '/ai/_ai.php';
$user=mg_require_permission('admin.settings.manage');
$pdo=mg_db();
function mg_admin_ai_provider(PDO $pdo,string $key):array{$stmt=$pdo->prepare('SELECT * FROM ai_providers WHERE provider_key=? LIMIT 1');$stmt->execute([$key]);$row=$stmt->fetch(PDO::FETCH_ASSOC);if(!$row)mg_fail('Unknown AI provider.',422);return $row;}
function mg_admin_ai_save_provider(PDO $pdo,array $input):void{$key=strtolower(trim((string)($input['provider_key']??'')));if(!preg_match('/^[a-z0-9_-]{2,80}$/',$key))mg_fail('Invalid provider key.',422);$provider=mg_admin_ai_provider($pdo,$key);$pdo->prepare('UPDATE ai_providers SET enabled=?,rate_limit_per_minute=?,rate_limit_per_hour=?,rate_limit_per_day=?,user_rate_limit_per_hour=?,user_rate_limit_per_day=?,agent_rate_limit_per_hour=?,agent_rate_limit_per_day=?,updated_at=NOW() WHERE id=?')->execute([!empty($input['enabled'])?1:0,mg_ai_limit_int($input['rate_limit_per_minute']??null,(int)$provider['rate_limit_per_minute']),mg_ai_limit_int($input['rate_limit_per_hour']??null,(int)$provider['rate_limit_per_hour']),mg_ai_limit_int($input['rate_limit_per_day']??null,(int)$provider['rate_limit_per_day']),mg_ai_limit_int($input['user_rate_limit_per_hour']??null,(int)$provider['user_rate_limit_per_hour']),mg_ai_limit_int($input['user_rate_limit_per_day']??null,(int)$provider['user_rate_limit_per_day']),mg_ai_limit_int($input['agent_rate_limit_per_hour']??null,(int)$provider['agent_rate_limit_per_hour']),mg_ai_limit_int($input['agent_rate_limit_per_day']??null,(int)$provider['agent_rate_limit_per_day']),(int)$provider['id']]);$models=is_array($input['models']??null)?$input['models']:[];$default=trim((string)($input['default_model_key']??''));if($default!=='')$pdo->prepare('UPDATE ai_models SET is_default=0 WHERE provider_id=?')->execute([(int)$provider['id']]);foreach($models as $model){if(!is_array($model))continue;$modelKey=trim((string)($model['model_key']??''));if($modelKey===''||strlen($modelKey)>120)continue;$display=trim((string)($model['display_name']??$modelKey));$enabled=!empty($model['enabled'])?1:0;$isDefault=$default!==''?($modelKey===$default?1:0):(!empty($model['is_default'])?1:0);$sort=mg_ai_limit_int($model['sort_order']??100,100,100000);$lookup=$pdo->prepare('SELECT id FROM ai_models WHERE provider_id=? AND model_key=? LIMIT 1');$lookup->execute([(int)$provider['id'],$modelKey]);$id=$lookup->fetchColumn();if($id){$pdo->prepare('UPDATE ai_models SET display_name=?,enabled=?,is_default=?,sort_order=?,updated_at=NOW() WHERE id=?')->execute([$display?:$modelKey,$enabled,$isDefault,$sort,(int)$id]);}else{$pdo->prepare('INSERT INTO ai_models (public_id,provider_id,model_key,display_name,enabled,is_default,sort_order,created_at,updated_at) VALUES (?,?,?,?,?,?,?,NOW(),NOW())')->execute([mg_public_uuid(),(int)$provider['id'],$modelKey,$display?:$modelKey,$enabled,$isDefault,$sort]);}}}
if(($_SERVER['REQUEST_METHOD']??'GET')==='GET')mg_ok(mg_ai_public_settings($pdo));
mg_require_method('POST');$input=mg_input();mg_require_csrf_for_write($input);$providers=is_array($input['providers']??null)?$input['providers']:[];try{$pdo->beginTransaction();foreach($providers as $provider){if(is_array($provider))mg_admin_ai_save_provider($pdo,$provider);}$pdo->commit();mg_audit('admin.ai_settings_updated','ai_settings',['provider_count'=>count($providers)],(int)$user['id']);mg_ok(mg_ai_public_settings($pdo),'AI provider settings saved.');}catch(Throwable $e){if($pdo->inTransaction())$pdo->rollBack();mg_fail('Unable to save AI provider settings right now.',500);}